[{"name_path": "HandleExecveEvent", "kind": "Method", "relative_path": "orca-runtime-sensor/pkg/containermonitor/monitor.go", "body_location": {"start_line": 159, "end_line": 201}, "body": "func (cm *ContainerMonitor) HandleExecveEvent(event *events.ExecveEvent) {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	if event.PID != 1 { // event.PID is NSPID
		return // Not an init process
	}

	cgroupPath, exists := cm.pendingCgroups[event.CgroupID]
	if !exists {
		if _, isAlreadyActive := cm.activeContainers[event.CgroupID]; isAlreadyActive {
			slog.Debug("ContainerMonitor: ExecveEvent for already known container",
				"cgroupID", event.CgroupID, "hostPID", event.HostPID)
		}
		return
	}

	delete(cm.pendingCgroups, event.CgroupID)

	containerID, err := procutils.ExtractContainerIDFromCgroupPath(cgroupPath)
	if err != nil {
		slog.Debug("ContainerMonitor: Failed to extract ContainerID from cgroup path, not treating as container init",
			"cgroupPath", cgroupPath, "cgroupID", event.CgroupID, "err", err)
		return
	}

	info := DetectedContainerInfo{
		CgroupID:    event.CgroupID,
		ContainerID: containerID,
		HostPID:     event.HostPID,
	}
	// Overwrite is acceptable here — if the scan already added this container,
	// AttachToContainerLibs has its own dedup via containerLinks.
	cm.activeContainers[event.CgroupID] = info

	slog.Info("ContainerMonitor: New container's init process detected!",
		"cgroupID", info.CgroupID,
		"containerID", info.ContainerID,
		"hostPID", info.HostPID,
		"exe", event.ExePath)

	cm.trySendAction(containerAction{action: actionAttach, cgroupID: info.CgroupID, hostPID: info.HostPID})
}"}]

[{"name_path": "worker", "kind": "Method", "relative_path": "orca-runtime-sensor/pkg/containermonitor/monitor.go", "body_location": {"start_line": 92, "end_line": 134}, "body": "func (cm *ContainerMonitor) worker(ctx context.Context) {
	defer close(cm.done)

	// Scan for pre-existing containers concurrently so the worker immediately
	// starts draining actionCh. The scan sends attach actions through actionCh,
	// so all AttachToContainerLibs calls are serialized in this worker goroutine.
	// initExistingContainerScan is platform-specific (unix/windows).
	go func() {
		defer cm.scanWg.Done()
		cm.initExistingContainerScan()
	}()

	for action := range cm.actionCh {
		if cm.sslProbe == nil {
			continue
		}
		switch action.action {
		case actionAttach:
			if cm.Enabled != nil && !cm.Enabled() {
				slog.Debug("ContainerMonitor: skipping attach, feature disabled",
					"cgroupID", action.cgroupID)
				continue
			}
			cm.mu.Lock()
			_, stillActive := cm.activeContainers[action.cgroupID]
			cm.mu.Unlock()
			if !stillActive {
				slog.Debug("ContainerMonitor: skipping attach for removed container",
					"cgroupID", action.cgroupID)
				continue
			}
			if err := cm.sslProbe.AttachToContainerLibs(action.cgroupID, action.hostPID); err != nil {
				slog.Error("Failed to attach SSL probes to container",
					"cgroupID", action.cgroupID, "err", err)
			}
		case actionDetach:
			if err := cm.sslProbe.DetachFromContainerLibs(action.cgroupID); err != nil {
				slog.Error("ContainerMonitor: Error detaching SSL probes",
					"cgroupID", action.cgroupID, "err", err)
			}
		}
	}
}"}]

