[{"name_path": "NewContainerMonitor", "kind": "Function", "relative_path": "orca-runtime-sensor/pkg/containermonitor/monitor.go", "body_location": {"start_line": 61, "end_line": 73}, "body": "func NewContainerMonitor(sslProbe BPFSslProbeInterface, procfsDir string, hostRoot string, procUtils *procutils.ProcUtils) *ContainerMonitor {
	return &ContainerMonitor{
		pendingCgroups:   make(map[uint64]string),
		activeContainers: make(map[uint64]DetectedContainerInfo),
		sslProbe:         sslProbe,
		actionCh:         make(chan containerAction, 128),
		done:             make(chan struct{}),
		stopCh:           make(chan struct{}),
		procfsDir:        procfsDir,
		hostRoot:         hostRoot,
		procUtils:        procUtils,
	}
}"}]

[{"name_path": "HandleCgroupRmdirEvent", "kind": "Method", "relative_path": "orca-runtime-sensor/pkg/containermonitor/monitor.go", "body_location": {"start_line": 204, "end_line": 228}, "body": "func (cm *ContainerMonitor) HandleCgroupRmdirEvent(event *events.CgroupRmdirEvent) {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	info, isActive := cm.activeContainers[event.CgroupID]
	if !isActive {
		if _, isPending := cm.pendingCgroups[event.CgroupID]; isPending {
			slog.Debug("ContainerMonitor: Cgroup removed while pending, cleaning up", "cgroupID", event.CgroupID)
			delete(cm.pendingCgroups, event.CgroupID)
		} else {
			slog.Debug("ContainerMonitor: Received rmdir for untracked cgroup", "cgroupID", event.CgroupID)
		}
		return
	}

	slog.Info("ContainerMonitor: Container terminated, cleaning up SSL probes",
		"cgroupID", info.CgroupID,
		"containerID", info.ContainerID,
		"hostPID", info.HostPID)

	delete(cm.activeContainers, event.CgroupID)
	delete(cm.pendingCgroups, event.CgroupID)

	cm.trySendAction(containerAction{action: actionDetach, cgroupID: event.CgroupID})
}"}]

[{"name_path": "trySendAction", "kind": "Method", "relative_path": "orca-runtime-sensor/pkg/containermonitor/monitor.go", "body_location": {"start_line": 138, "end_line": 147}, "body": "func (cm *ContainerMonitor) trySendAction(action containerAction) {
	select {
	case <-cm.stopCh:
		return
	case cm.actionCh <- action:
	default:
		slog.Warn("ContainerMonitor: action channel full, dropping action",
			"action", action.action, "cgroupID", action.cgroupID)
	}
}"}]

[{"name_path": "ListContainers", "kind": "Method", "relative_path": "orca-runtime-sensor/pkg/containermonitor/monitor.go", "body_location": {"start_line": 240, "end_line": 249}, "body": "func (cm *ContainerMonitor) ListContainers() []DetectedContainerInfo {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	containers := make([]DetectedContainerInfo, 0, len(cm.activeContainers))
	for _, info := range cm.activeContainers {
		containers = append(containers, info)
	}
	return containers
}"}]

